I can't get the file upload to work when using `ng-file-select`. It's like the file is never added to the associated model. What's strange is that `ng-file-drop` is working without any issues.

My html looks like this:

```
<form id="new-project-form" name="form" ng-submit="create(project)" novalidate="novalidate" class="form-horizontal">
  <div ng-file-drop="ng-file-drop" ng-model="files" drag-over-class="dragover" class="drop-box">
    <fieldset>
      <legend translate="subproject.new"></legend>
      <div class="form-group">
        <label for="inputFile" translate="subproject.file" class="col-xs-2 control-label"></label>
        <div class="col-xs-10">
          <input type="file" ng-file-select="" ng-model="files" translate="subproject.form.select_file"/>
          <div class="progress progress-striped active">
            <div ng-style="progress" class="progress-bar"></div>
          </div>
          <div ng-repeat="file in uploadedFiles">
            <div class="row">
              <div ng-click="deleteFile(file)" class="col-xs-1"><img src="delete.png" class="delete"/></div>
              <div class="col-xs-11"><span>{{file.name}}</span></div>
            </div>
          </div>
        </div>
      </div>
    </fieldset>
  </div>
</form>
```

And this is the part of my controller that handles the file upload:

```
$scope.progress = {
    'width': '0%'
};
$scope.uploadedFiles = [];
$scope.project = {
    'file-ids': [],
    email: authenticationService.loggedInUser()
};
$scope.$watch('files', function(newValue, oldValue) {
      if (newValue === void 0) {
        return;
      }
      $scope.upload = $upload.upload({
        url: "some-upload-url",
        file: $scope.files
      }).progress(function(evt) {
         $scope.progress = {
           'width': parseInt(100.0 * evt.loaded / evt.total) + '%'
         };
      }).success(function(data, status, headers, config) {
          $scope.project['file-ids'].push(data.files[0].id);
          $scope.uploadedFiles.push(data.files[0]);
          $scope.progress = {
              'width': '0%'
          };
      });
});
```

